ALL_ADJECTIVES = ADJECTIVES + ADJECTIVES2

raw = []
raw += make_questions(ALL_NOUNS, ALL_NOUNS)
raw += make_questions(ALL_VERBS, ALL_VERBS)
raw += make_questions(ALL_ADJECTIVES, ALL_ADJECTIVES)
raw += make_questions(ADVERBS, ADVERBS)

# Deduplicate
seen, unique = set(), []
for q in raw:
    k = q["question"]
    if k not in seen:
        seen.add(k)
        unique.append(q)

random.shuffle(unique)

questions = [{"id": f"v{i+1:04d}", **q} for i, q in enumerate(unique)]
print(f"Total unique questions: {len(questions)}")

out = Path(__file__).parent / "data" / "content.json"
out.parent.mkdir(exist_ok=True)
with open(out, "w", encoding="utf-8") as f:
    json.dump(questions, f, ensure_ascii=False, indent=2)
print(f"Saved to {out}")

state = Path(__file__).parent / "data" / "state.json"
if not state.exists():
    state.write_text(json.dumps({"posted": []}, indent=2))
    print("Created state.json")
